// Cloudflare Worker: API Integration with SendGrid and Stripe
// wrangler.toml configuration should include:
// [vars]
// ALLOWED_ORIGINS = "https://yourdomain.com"
// 
// [secrets]
// SENDGRID_API_KEY
// STRIPE_SECRET_KEY
// API_AUTH_TOKEN

export default {
  async fetch(request, env, ctx) {
    const corsHeaders = {
      'Access-Control-Allow-Origin': env.ALLOWED_ORIGINS || '*',
      'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
      'Access-Control-Allow-Headers': 'Content-Type, Authorization',
      'Access-Control-Max-Age': '86400',
    };

    // Handle CORS preflight
    if (request.method === 'OPTIONS') {
      return new Response(null, { status: 204, headers: corsHeaders });
    }

    try {
      // Authenticate the request
      const authResult = authenticateRequest(request, env);
      if (!authResult.success) {
        return jsonResponse(401, { error: authResult.message }, corsHeaders);
      }

      const url = new URL(request.url);
      const path = url.pathname;

      // Route handling
      switch (true) {
        // Health check
        case path === '/' && request.method === 'GET':
          return jsonResponse(200, { status: 'ok', service: 'api-integration-worker' }, corsHeaders);

        // SendGrid Email Routes
        case path === '/api/email/send' && request.method === 'POST':
          return await handleSendEmail(request, env, corsHeaders);

        case path === '/api/email/send-template' && request.method === 'POST':
          return await handleSendTemplateEmail(request, env, corsHeaders);

        // Stripe Payment Routes
        case path === '/api/payments/create-intent' && request.method === 'POST':
          return await handleCreatePaymentIntent(request, env, corsHeaders);

        case path === '/api/payments/create-customer' && request.method === 'POST':
          return await handleCreateCustomer(request, env, corsHeaders);

        case path === '/api/payments/create-subscription' && request.method === 'POST':
          return await handleCreateSubscription(request, env, corsHeaders);

        case path === '/api/payments/refund' && request.method === 'POST':
          return await handleRefund(request, env, corsHeaders);

        // Stripe Webhook (no auth required - uses Stripe signature)
        case path === '/api/webhooks/stripe' && request.method === 'POST':
          return await handleStripeWebhook(request, env, corsHeaders);

        default:
          return jsonResponse(404, { error: 'Not found' }, corsHeaders);
      }
    } catch (error) {
      console.error('Unhandled error:', error.message, error.stack);
      return jsonResponse(500, {
        error: 'Internal server error',
        message: error.message,
      }, corsHeaders);
    }
  },
};

// ==================== Authentication ====================

function authenticateRequest(request, env) {
  const url = new URL(request.url);

  // Skip auth for webhook endpoints and health check
  if (url.pathname === '/api/webhooks/stripe' || url.pathname === '/') {
    return { success: true };
  }

  const authHeader = request.headers.get('Authorization');
  if (!authHeader) {
    return { success: false, message: 'Missing Authorization header' };
  }

  const [scheme, token] = authHeader.split(' ');
  if (scheme !== 'Bearer' || !token) {
    return { success: false, message: 'Invalid Authorization format. Use: Bearer <token>' };
  }

  if (token !== env.API_AUTH_TOKEN) {
    return { success: false, message: 'Invalid API token' };
  }

  return { success: true };
}

// ==================== SendGrid Email Handlers ====================

async function handleSendEmail(request, env, corsHeaders) {
  const body = await parseJsonBody(request);
  if (body.error) {
    return jsonResponse(400, { error: body.error }, corsHeaders);
  }

  const { to, from, subject, text, html } = body.data;

  // Validate required fields
  const validation = validateRequired({ to, from, subject }, ['to', 'from', 'subject']);
  if (!validation.valid) {
    return jsonResponse(400, { error: `Missing required fields: ${validation.missing.join(', ')}` }, corsHeaders);
  }

  if (!text && !html) {
    return jsonResponse(400, { error: 'Either text or html content is required' }, corsHeaders);
  }

  // Validate email format
  if (!isValidEmail(to) || !isValidEmail(from)) {
    return jsonResponse(400, { error: 'Invalid email address format' }, corsHeaders);
  }

  const sendGridPayload = {
    personalizations: [
      {
        to: [{ email: to }],
      },
    ],
    from: { email: from },
    subject: subject,
    content: [],
  };

  if (text) {
    sendGridPayload.content.push({ type: 'text/plain', value: text });
  }
  if (html) {
    sendGridPayload.content.push({ type: 'text/html', value: html });
  }

  const result = await sendGridRequest('/v3/mail/send', 'POST', sendGridPayload, env);

  if (!result.success) {
    return jsonResponse(result.status || 502, {
      error: 'Failed to send email',
      details: result.error,
    }, corsHeaders);
  }

  return jsonResponse(200, { success: true, message: 'Email sent successfully' }, corsHeaders);
}

async function handleSendTemplateEmail(request, env, corsHeaders) {
  const body = await parseJsonBody(request);
  if (body.error) {
    return jsonResponse(400, { error: body.error }, corsHeaders);
  }

  const { to, from, templateId, dynamicTemplateData } = body.data;

  const validation = validateRequired({ to, from, templateId }, ['to', 'from', 'templateId']);
  if (!validation.valid) {
    return jsonResponse(400, { error: `Missing required fields: ${validation.missing.join(', ')}` }, corsHeaders);
  }

  if (!isValidEmail(to) || !isValidEmail(from)) {
    return jsonResponse(400, { error: 'Invalid email address format' }, corsHeaders);
  }

  const sendGridPayload = {
    personalizations: [
      {
        to: [{ email: to }],
        dynamic_template_data: dynamicTemplateData || {},
      },
    ],
    from: { email: from },
    template_id: templateId,
  };

  const result = await sendGridRequest('/v3/mail/send', 'POST', sendGridPayload, env);

  if (!result.success) {
    return jsonResponse(result.status || 502, {
      error: 'Failed to send template email',
      details: result.error,
    }, corsHeaders);
  }

  return jsonResponse(200, { success: true, message: 'Template email sent successfully' }, corsHeaders);
}

// ==================== Stripe Payment Handlers ====================

async function handleCreatePaymentIntent(request, env, corsHeaders) {
  const body = await parseJsonBody(request);
  if (body.error) {
    return jsonResponse(400, { error: body.error }, corsHeaders);
  }

  const { amount, currency, customerId, metadata, automaticPaymentMethods } = body.data;

  if (!amount || !currency) {
    return jsonResponse(400, { error: 'Missing required fields: amount, currency' }, corsHeaders);
  }

  if (typeof amount !== 'number' || amount <= 0) {
    return jsonResponse(400, { error: 'Amount must be a positive number (in smallest currency unit, e.g., cents)' }, corsHeaders);
  }

  const params = new URLSearchParams();
  params.append('amount', amount.toString());
  params.append('currency', currency.toLowerCase());

  if (customerId) {
    params.append('customer', customerId);
  }

  if (automaticPaymentMethods !== false) {
    params.append('automatic_payment_methods[enabled]', 'true');
  }

  if (metadata && typeof metadata === 'object') {
    for (const [key, value] of Object.entries(metadata)) {
      params.append(`metadata[${key}]`, String(value));
    }
  }

  const result = await stripeRequest('/v1/payment_intents', 'POST', params, env);

  if (!result.success) {
    return jsonResponse(result.status || 502, {
      error: 'Failed to create payment intent',
      details: result.error,
    }, corsHeaders);
  }

  return jsonResponse(200, {
    success: true,
    paymentIntent: {
      id: result.data.id,
      clientSecret: result.data.client_secret,
      amount: result.data.amount,
      currency: result.data.currency,
      status: result.data.status,
    },
  }, corsHeaders);
}

async function handleCreateCustomer(request, env, corsHeaders) {
  const body = await parseJsonBody(request);
  if (body.error) {
    return jsonResponse(400, { error: body.error }, corsHeaders);
  }

  const { email, name, phone, metadata } = body.data;

  if (!email) {
    return jsonResponse(400, { error: 'Missing required field: email' }, corsHeaders);
  }

  if (!isValidEmail(email)) {
    return jsonResponse(400, { error: 'Invalid email address format' }, corsHeaders);
  }

  const params = new URLSearchParams();
  params.append('email', email);

  if (name) params.append('name', name);
  if (phone) params.append('phone', phone);

  if (metadata && typeof metadata === 'object') {
    for (const [key, value] of Object.entries(metadata)) {
      params.append(`metadata[${key}]`, String(value));
    }
  }

  const result = await stripeRequest('/v1/customers', 'POST', params, env);

  if (!result.success) {
    return jsonResponse(result.status || 502, {
      error: 'Failed to create customer',
      details: result.error,
    }, corsHeaders);
  }

  return jsonResponse(200, {
    success: true,
    customer: {
      id: result.data.id,
      email: result.data.email,
      name: result.data.name,
    },
  }, corsHeaders);
}

async function handleCreateSubscription(request, env, corsHeaders) {
  const body = await parseJsonBody(request);
  if (body.error) {
    return jsonResponse(400, { error: body.error }, corsHeaders);
  }

  const { customerId, priceId, trialPeriodDays, metadata } = body.data;

  const validation = validateRequired({ customerId, priceId }, ['customerId', 'priceId']);
  if (!validation.valid) {
    return jsonResponse(400, { error: `Missing required fields: ${validation.missing.join(', ')}` }, corsHeaders);
  }

  const params = new URLSearchParams();
  params.append('customer', customerId);
  params.append('items[0][price]', priceId);
  params.append('payment_behavior', 'default_incomplete');
  params.append('expand[]', 'latest_invoice.payment_intent');

  if (trialPeriodDays && trialPeriodDays > 0) {
    params.append('trial_period_days', trialPeriodDays.toString());
  }

  if (metadata && typeof metadata === 'object') {
    for (const [key, value] of Object.entries(metadata)) {
      params.append(`metadata[${key}]`, String(value));
    }
  }

  const result = await stripeRequest('/v1/subscriptions', 'POST', params, env);

  if (!result.success) {
    return jsonResponse(result.status || 502, {
      error: 'Failed to create subscription',
      details: result.error,
    }, corsHeaders);
  }

  const subscription = result.data;
  const responseData = {
    success: true,
    subscription: {
      id: subscription.id,
      status: subscription.status,
      currentPeriodEnd: subscription.current_period_end,
    },
  };

  // Include client secret for incomplete subscriptions
  if (subscription.latest_invoice?.payment_intent?.client_secret) {
    responseData.subscription.clientSecret = subscription.latest_invoice.payment_intent.client_secret;
  }

  return jsonResponse(200, responseData, corsHeaders);
}

async function handleRefund(request, env, corsHeaders) {
  const body = await parseJsonBody(request);
  if (body.error) {
    return jsonResponse(400, { error: body.error }, corsHeaders);
  }

  const { paymentIntentId, amount, reason } = body.data;

  if (!paymentIntentId) {
    return jsonResponse(400, { error: 'Missing required field: paymentIntentId' }, corsHeaders);
  }

  const params = new URLSearchParams();
  params.append('payment_intent', paymentIntentId);

  if (amount && amount > 0) {
    params.append('amount', amount.toString());
  }

  if (reason) {
    const validReasons = ['duplicate', 'fraudulent', 'requested_by_customer'];
    if (validReasons.includes(reason)) {
      params.append('reason', reason);
    }
  }

  const result = await stripeRequest('/v1/refunds', 'POST', params, env);

  if (!result.success) {
    return jsonResponse(result.status || 502, {
      error: 'Failed to process refund',
      details: result.error,
    }, corsHeaders);
  }

  return jsonResponse(200, {
    success: true,
    refund: {
      id: result.data.id,
      amount: result.data.amount,
      currency: result.data.currency,
      status: result.data.status,
    },
  }, corsHeaders);
}

// ==================== Stripe Webhook Handler ====================

async function handleStripeWebhook(request, env, corsHeaders) {
  const signature = request.headers.get('stripe-signature');
  if (!signature) {
    return jsonResponse(400, { error: 'Missing Stripe signature' }, corsHeaders);
  }

  const rawBody = await request.text();

  // Verify webhook signature
  const isValid = await verifyStripeSignature(rawBody, signature, env.STRIPE_WEBHOOK_SECRET);
  if (!isValid) {
    return jsonResponse(400, { error: 'Invalid webhook signature' }, corsHeaders);
  }

  let event;
  try {
    event = JSON.parse(rawBody);
  } catch (e) {
    return jsonResponse(400, { error: 'Invalid JSON payload' }, corsHeaders);
  }

  console.log(`Stripe webhook received: ${event.type}`, JSON.stringify({ id: event.id }));

  // Handle different event types
  switch (event.type) {
    case 'payment_intent.succeeded':
      await handlePaymentIntentSucceeded(event.data.object, env);
      break;

    case 'payment_intent.payment_failed':
      await handlePaymentIntentFailed(event.data.object, env);
      break;

    case 'customer.subscription.created':
    case 'customer.subscription.updated':
      await handleSubscriptionUpdated(event.data.object, env);
      break;

    case 'customer.subscription.deleted':
      await handleSubscriptionDeleted(event.data.object, env);
      break;

    case 'invoice.payment_succeeded':
      await handleInvoicePaymentSucceeded(event.data.object, env);
      break;

    case 'invoice.payment_failed':
      await handleInvoicePaymentFailed(event.data.object, env);
      break;

    default:
      console.log(`Unhandled event type: ${event.type}`);
  }

  return jsonResponse(200, { received: true }, corsHeaders);
}

