// ==================== API Client Functions ====================

async function sendGridRequest(endpoint, method, body, env) {
  const url = `https://api.sendgrid.com${endpoint}`;

  try {
    const response = await fetch(url, {
      method,
      headers: {
        'Authorization': `Bearer ${env.SENDGRID_API_KEY}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(body),
    });

    // SendGrid returns 202 for successful email sends
    if (response.status === 202 || response.status === 200 || response.status === 201) {
      let data = null;
      const contentType = response.headers.get('content-type');
      if (contentType && contentType.includes('application/json')) {
        try {
          data = await response.json();
        } catch (e) {
          // Some successful SendGrid responses have no body
        }
      }
      return { success: true, data };
    }

    let errorData;
    try {
      errorData = await response.json();
    } catch (e) {
      errorData = { message: `HTTP ${response.status}` };
    }

    console.error('SendGrid API error:', JSON.stringify(errorData));
    return {
      success: false,
      status: response.status,
      error: errorData.errors?.[0]?.message || errorData.message || 'SendGrid API error',
    };
  } catch (error) {
    console.error('SendGrid request failed:', error.message);
    return {
      success: false,
      status: 502,
      error: 'Failed to connect to SendGrid API',
    };
  }
}

async function stripeRequest(endpoint, method, params, env) {
  const url = `https://api.stripe.com${endpoint}`;

  try {
    const response = await fetch(url, {
      method,
      headers: {
        'Authorization': `Basic ${btoa(env.STRIPE_SECRET_KEY + ':')}`,
        'Content-Type': 'application/x-www-form-urlencoded',
        'Stripe-Version': '2023-10-16',
      },
      body: params.toString(),
    });

    const data = await response.json();

    if (response.ok) {
      return { success: true, data };
    }

    console.error('Stripe API error:', JSON.stringify(data.error));
    return {
      success: false,
      status: response.status,
      error: data.error?.message || 'Stripe API error',
    };
  } catch (error) {
    console.error('Stripe request failed:', error.message);
    return {
      success: false,
      status: 502,
      error: 'Failed to connect to Stripe API',
    };
  }
}

// ==================== Stripe Webhook Signature Verification ====================

async function verifyStripeSignature(payload, signatureHeader, webhookSecret) {
  if (!webhookSecret) {
    console.warn('STRIPE_WEBHOOK_SECRET not configured, skipping signature verification');
    return true;
  }

  try {
    const parts = signatureHeader.split(',').reduce((acc, part) => {
      const [key, value] = part.split('=');
      acc[key.trim()] = value;
      return acc;
    }, {});

    const timestamp = parts['t'];
    const expectedSignature = parts['v1'];

    if (!timestamp || !expectedSignature) {
      return false;
    }

    // Check timestamp tolerance (5 minutes)
    const currentTime = Math.floor(Date.now() / 1000);
    if (Math.abs(currentTime - parseInt(timestamp)) > 300) {
      console.error('Webhook timestamp outside tolerance');
      return false;
    }

    // Compute expected signature
    const signedPayload = `${timestamp}.${payload}`;
    const key = await crypto.subtle.importKey(
      'raw',
      new TextEncoder().encode(webhookSecret),
      { name: 'HMAC', hash: 'SHA-256' },
      false,
      ['sign']
    );

    const signatureBuffer = await crypto.subtle.sign(
      'HMAC',
      key,
      new TextEncoder().encode(signedPayload)
    );

    const computedSignature = Array.from(new Uint8Array(signatureBuffer))
      .map(b => b.toString(16).padStart(2, '0'))
      .join('');

    return timingSafeEqual(computedSignature, expectedSignature);
  } catch (error) {
    console.error('Signature verification error:', error.message);
    return false;
  }
}

function timingSafeEqual(a, b) {
  if (a.length !== b.length) {
    return false;
  }
  let result = 0;
  for (let i = 0; i < a.length; i++) {
    result |= a.charCodeAt(i) ^ b.charCodeAt(i);
  }
  return result === 0;
}

// ==================== Utility Functions ====================

function jsonResponse(status, body, corsHeaders = {}) {
  return new Response(JSON.stringify(body), {
    status,
    headers: {
      'Content-Type': 'application/json',
      ...corsHeaders,
    },
  });
}

async function parseJsonBody(request) {
  try {
    const contentType = request.headers.get('content-type');
    if (!contentType || !contentType.includes('application/json')) {
      return { error: 'Content-Type must be application/json' };
    }
    const data = await request.json();
    if (!data || typeof data !== 'object') {
      return { error: 'Request body must be a JSON object' };
    }
    return { data };
  } catch (e) {
    return { error: 'Invalid JSON in request body' };
  }
}

function validateRequired(obj, requiredFields) {
  const missing = requiredFields.filter(field => !obj[field]);
  return {
    valid: missing.length === 0,
    missing,
  };
}

function isValidEmail(email) {
  if (!email || typeof email !== 'string') return false;
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
}